import java.io.File;
import java.io.FileReader;
import java.io.IOException;
import java.nio.file.Path;
import java.nio.file.Paths;

public class SecurePathTraversal {

    public static void main(String[] args) {
        String userInput = "../etc/passwd";
        String baseDirectory = "/path/to/directory/";

        try {
            Path basePath = Paths.get(baseDirectory).toRealPath();
            Path userInputPath = basePath.resolve(userInput).normalize();

            if (!userInputPath.startsWith(basePath)) {
                System.out.println("Access denied. Invalid path specified.");
                return;
            }

            File file = userInputPath.toFile();
            FileReader reader = new FileReader(file);

            int data;
            while ((data = reader.read()) != -1) {
                System.out.print((char) data);
            }

            reader.close();
        } catch (IOException e) {
            System.out.println("Error reading file: " + e.getMessage());
        }
    }
}

